def solve(arg1: dict) -> list[dict]:
    project_members = {
        '123': [
            {'id': '1', 'name': 'Alice', 'role': 'admin'},
            {'id': '2', 'name': 'Bob', 'role': 'member'}
        ]
    }

    invites = {
        '123': [
            {'id': '1', 'email': 'invitee@example.com', 'status': 'pending'}
        ]
    }

    project_id = arg1.get('projectId')
    fields = arg1.get('fields')

    if fields == 'id,name,role':
        if project_id in project_members:
            return project_members[project_id]

    return None

def add_project_member(project_id: str, member: dict) -> dict:
    if project_id not in project_members:
        project_members[project_id] = []
    project_members[project_id].append(member)
    return member

def get_invites(project_id: str) -> list[dict]:
    if project_id in invites:
        return invites[project_id]
    return []

def accept_invite(project_id: str, invite_id: str) -> dict:
    if project_id in invites:
        for invite in invites[project_id]:
            if invite['id'] == invite_id:
                invite['status'] = 'accepted'
                return {'status': 'accepted'}
    return {'status': 'not found'}

def delete_member(project_id: str, member_id: str) -> dict:
    if project_id in project_members:
        project_members[project_id] = [
            member for member in project_members[project_id] if member['id'] != member_id
        ]
        return {'status': 'deleted'}
    return {'status': 'not found'}
